const output = $input.first().json;
let result;
try {
  const lines = (output.stdout || '').trim().split('\n');
  const lastLine = lines[lines.length - 1];
  result = JSON.parse(lastLine);
} catch(e) {
  result = { nuovi: 0, totale: 0, annunci: [] };
}
return [{ json: result }];

const data = $input.first().json;
const annunci = data.annunci || [];

let htmlCards = annunci.map(a => `
  <div style="background:#1e2a3a;border:1px solid #2d3f55;border-radius:8px;padding:14px;margin-bottom:12px;">
    <strong style="color:#e0e0e0;">${a.titolo || 'Annuncio'}</strong><br/>
    <span style="color:#00d4ff;font-size:18px;font-weight:bold;">€${a.prezzo}/mese</span><br/>
    <span style="color:#a0b4c8;font-size:12px;">📍 ${a.comune} · 🚗 ${(a.distanza_km||0).toFixed(1)} km · 📐 ${a.superficie_mq||'N/D'} m²</span><br/>
    <a href="${a.url}" style="background:#00d4ff;color:#0a0e1a;padding:5px 12px;border-radius:4px;text-decoration:none;font-size:12px;font-weight:bold;display:inline-block;margin-top:8px;">🔗 Vedi annuncio</a>
  </div>`).join('');

const html = `<!DOCTYPE html><html><body style="background:#0a0e1a;color:#e0e0e0;font-family:Arial,sans-serif;padding:20px;">
  <h2 style="color:#00d4ff;">🏠 Casa Finder BGY1 — ${annunci.length} nuov${annunci.length===1?'o':'i'} annunci</h2>
  ${htmlCards}
  <p style="color:#4a5568;font-size:11px;margin-top:20px;">Aggiornamento automatico ogni ora · Cividate al Piano ±30km</p>
</body></html>`;

return [{ json: { html, count: annunci.length, subject: `🏠 Casa Finder: ${annunci.length} nuov${annunci.length===1?'o':'i'} annunci` } }];
